import{c as i,Q as e,j as s,m as l}from"./chunks/framework.Bhbi9jCp.js";const c=JSON.parse('{"title":"SFU 心智:mediasoup / LiveKit / Janus","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/24-SFU心智-mediasoup-LiveKit-Janus.md","filePath":"mediaTechLearning/24-SFU心智-mediasoup-LiveKit-Janus.md","lastUpdated":1780887690000}'),t={name:"mediaTechLearning/24-SFU心智-mediasoup-LiveKit-Janus.md"};function n(p,a,o,r,u,d){return e(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="sfu-心智-mediasoup-livekit-janus" tabindex="-1">SFU 心智:mediasoup / LiveKit / Janus <a class="header-anchor" href="#sfu-心智-mediasoup-livekit-janus" aria-label="Permalink to &quot;SFU 心智:mediasoup / LiveKit / Janus&quot;">​</a></h1><p>SFU 的核心不是&quot;转发视频&quot;,而是管理一堆 RTP 流、订阅关系和质量反馈。</p><blockquote><p>一句话先记住:<strong>SFU 不混画面,它决定谁的哪些 RTP 层转给谁</strong>。会议体验好不好,很大程度取决于 SFU 的订阅、带宽估计和降级策略。</p></blockquote><hr><h2 id="一、sfu-基本对象" tabindex="-1">一、SFU 基本对象 <a class="header-anchor" href="#一、sfu-基本对象" aria-label="Permalink to &quot;一、SFU 基本对象&quot;">​</a></h2><p>不同项目命名不同,但抽象类似:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Room</span></span>
<span class="line"><span>  Peer / Participant</span></span>
<span class="line"><span>    Producer   上传的音视频</span></span>
<span class="line"><span>    Consumer   订阅的远端音视频</span></span>
<span class="line"><span>Transport      WebRTC 传输通道</span></span></code></pre></div><p>客户端上传 Track,服务端创建 Producer。其他人想看,就创建 Consumer。</p><hr><h2 id="二、sfu-转发什么" tabindex="-1">二、SFU 转发什么 <a class="header-anchor" href="#二、sfu-转发什么" aria-label="Permalink to &quot;二、SFU 转发什么&quot;">​</a></h2><p>SFU 主要处理:</p><ul><li>RTP 包转发</li><li>RTCP 反馈</li><li>带宽估计</li><li>Simulcast / SVC 层选择</li><li>关键帧请求</li><li>订阅关系</li></ul><p>它通常不做:</p><ul><li>解码画面</li><li>合成布局</li><li>美颜滤镜</li></ul><p>这些要么在客户端做,要么另接录制 / 转码服务。</p><hr><h2 id="三、mediasoup" tabindex="-1">三、mediasoup <a class="header-anchor" href="#三、mediasoup" aria-label="Permalink to &quot;三、mediasoup&quot;">​</a></h2><p>特点:</p><ul><li>Node.js 控制面 + C++ worker</li><li>抽象底层,灵活</li><li>适合自研会议系统</li></ul><p>代价:</p><ul><li>你要自己写房间、权限、信令、状态同步</li><li>学习曲线高</li></ul><p>适合需要深度定制的团队。</p><hr><h2 id="四、livekit" tabindex="-1">四、LiveKit <a class="header-anchor" href="#四、livekit" aria-label="Permalink to &quot;四、LiveKit&quot;">​</a></h2><p>特点:</p><ul><li>产品化程度高</li><li>房间、权限、SDK、录制、云部署生态完整</li><li>上手快</li></ul><p>代价:</p><ul><li>深度定制要跟框架走</li><li>部署和成本模型要理解</li></ul><p>适合快速做会议、语音房、互动直播。</p><hr><h2 id="五、janus" tabindex="-1">五、Janus <a class="header-anchor" href="#五、janus" aria-label="Permalink to &quot;五、Janus&quot;">​</a></h2><p>特点:</p><ul><li>C 写的 WebRTC server</li><li>插件化</li><li>历史久,适合网关类场景</li></ul><p>常见用途:</p><ul><li>WebRTC gateway</li><li>SIP / RTP / Streaming 适配</li><li>老系统接入</li></ul><hr><h2 id="六、录制怎么做" tabindex="-1">六、录制怎么做 <a class="header-anchor" href="#六、录制怎么做" aria-label="Permalink to &quot;六、录制怎么做&quot;">​</a></h2><p>SFU 转发不等于录制。录制常见方案:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 服务端订阅所有流 -&gt; 分轨录制 -&gt; 后处理合成</span></span>
<span class="line"><span>2. 启动 headless browser -&gt; 像用户一样进房间 -&gt; 录屏</span></span>
<span class="line"><span>3. SFU 提供 egress 服务 -&gt; 输出 MP4 / HLS</span></span></code></pre></div><p>分轨灵活,后处理复杂。浏览器录屏简单,资源重。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为 SFU 会自动混流</strong>——不会。</li><li><strong>不做活跃说话人和订阅控制</strong>——下行浪费。</li><li><strong>录制方案最后才想</strong>——架构会返工。</li><li><strong>忽略 TURN 和边缘部署</strong>——跨地域延迟高。</li><li><strong>没有 getStats + 服务端 RTP 指标</strong>——质量问题查不动。</li></ol><p>下一篇:<code>25-屏幕共享、录制与回放.md</code>。</p>`,44)])])}const m=i(t,[["render",n]]);export{c as __pageData,m as default};
